import{_ as e,c as o,o as l,a3 as i}from"./chunks/framework.BZwcwCMB.js";const m=JSON.parse('{"title":"关于 PR (Pull Request)","description":"","frontmatter":{"title":"关于 PR (Pull Request)","prev":{"text":"关于补全的 json 文件结构","link":"../completion/index.md"}},"headers":[],"relativePath":"zh-CN/contribute/index.md","filePath":"zh-CN/contribute/index.md"}'),c={name:"zh-CN/contribute/index.md"},t=i('<h1 id="关于-pr-pull-request" tabindex="-1">关于 PR (Pull Request) <a class="header-anchor" href="#关于-pr-pull-request" aria-label="Permalink to &quot;关于 PR (Pull Request)&quot;">​</a></h1><ol><li>前提: 你应该先阅读 <a href="./../completion/">关于补全的 json 文件结构</a></li><li>你应该 fork <a href="https://github.com/abgox/PSCompletions" target="_blank" rel="noreferrer">PSCompletions 仓库</a>，克隆到本地进行修改</li><li>只要到补全文件进行了修改，都需要更新其目录下的 <code>guid.txt</code> 文件 <ul><li>你可以手动运行 <code>New-Guid</code> 生成，将值填入此文件中</li><li>也可以直接运行 <code>.\\script\\updateGuid.ps1</code>，在弹出的 PowerShell 列表框中，选择此补全，并应用修改即可</li></ul></li><li>修改完成后，提交并创建 <code>PR</code></li></ol><h2 id="_1-更新-json-文件内容" tabindex="-1">1. 更新 json 文件内容 <a class="header-anchor" href="#_1-更新-json-文件内容" aria-label="Permalink to &quot;1. 更新 json 文件内容&quot;">​</a></h2><ul><li>完善补全的一些提示信息(<code>tip</code> 属性)</li><li>添加补全的一些缺失的命令 <ul><li>可以通过 <code>.\\script\\compareJson.ps1</code> 脚本来查看未完成的部分 <ul><li>以 <code>git</code> 举例</li><li>你可以使用以下命令查看 <code>zh-CN.json</code> 文件缺少的属性(相较于 <code>en-US.json</code> 文件) <ul><li><code>.\\script\\compareJson.ps1 .\\completions\\git\\language\\zh-CN.json .\\completions\\git\\language\\en-US.json</code></li></ul></li><li>如果是和 <code>config.json</code> 中配置的第一个语言对比，也可以省略第二个参数 <ul><li>一般都是和第一个语言对比，所以以下命令是最常见的用法</li><li><code>.\\script\\compareJson.ps1 .\\completions\\git\\language\\zh-CN.json</code></li></ul></li></ul></li></ul></li></ul><h2 id="_2-添加语言" tabindex="-1">2. 添加语言 <a class="header-anchor" href="#_2-添加语言" aria-label="Permalink to &quot;2. 添加语言&quot;">​</a></h2><ol><li>在项目的 <code>completions</code> 目录中找到你想要添加语言的补全</li><li>在其目录下的 <code>config.json</code> 文件中的 <code>language</code> 属性里添加像 <code>zh-CN</code> 这样的语言标识符</li><li>在 <code>language</code> 目录下添加与语言标识符同名的 json 文件 <ul><li>你可以将原有的一个 json 文件直接复制，改名即可</li></ul></li><li>翻译其中的 <code>tip</code> 属性的内容即可</li></ol><h2 id="_3-添加一个全新的命令补全" tabindex="-1">3. 添加一个全新的命令补全 <a class="header-anchor" href="#_3-添加一个全新的命令补全" aria-label="Permalink to &quot;3. 添加一个全新的命令补全&quot;">​</a></h2><ol><li>在项目根目录下运行 <code>.\\script\\create.ps1</code><ul><li>为了调试方便，<code>create.ps1</code> 会将创建的补全目录链接到实际 <code>PSCompletions</code> 的 <code>completions</code> 目录下 <ul><li>因此，必须先安装并导入 <code>PSCompletions</code> 模块，然后再运行 <code>create.ps1</code><ul><li><code>Install-Module PSCompletions -Scope CurrentUser</code></li><li><code>Import-Module PSCompletions</code></li></ul></li></ul></li><li>当提交 <code>PR</code> 并被合并后，你应该使用 <code>psc rm</code> 移除掉此补全，并使用 <code>psc add</code> 重新添加</li></ul></li><li>根据提示进行操作</li><li>修改新创建的补全</li><li>根据需求修改 <code>config.json</code></li></ol>',8),d=[t];function a(n,s,r,u,p,h){return l(),o("div",null,d)}const P=e(c,[["render",a]]);export{m as __pageData,P as default};
